                    }
                }

                if result["phone"] != nil { break }
            }
        }

        // 🔥 fallback: 전체 rows에서 찾기
        if result["phone"] == nil {

            for row in rows {

                if let phone = firstMatch(
                    row.fullText,
                    pattern: #"\(?\d{3}\)?[-.\s]?\d{3}[-.\s]?\d{4}"#
                ), isValidPhone(phone, context: row.fullText) {

                    result["phone"] = phone
                    break
                }
            }
        }

        // =========================
        // 🔥 PHONE MULTI-PARSE FIX (추가)
        // =========================
        if result["phone"] == nil {

            for row in headerRows {

                let matches = allMatches(
                    row.fullText,
                    pattern: #"\(?\d{3}\)?[-.\s]?\d{3}[-.\s]?\d{4}"#
                )

                if !matches.isEmpty {
                    // 첫 번째 유효한 번호 선택
