                    upper.contains("CUSTOMER AUTHORIZATION") {
                    break
                }

                let trimmed = rows[i].fullText.trimmingCharacters(in: .whitespacesAndNewlines)
                if !trimmed.isEmpty {
                    collected.append(trimmed)
                }
            }

            if !collected.isEmpty {
                result["description"] = collected.joined(separator: " ")
            }
        }

        result["type"] = "service"
        return result
    }

