//            print("🔎 PHRASE(raw) = '\(phrase)'")
//            print("   🧼 clean = '\(clean)'")
//            print("   🧩 words = \(words)")

            for w in words {
                // ✅ single-word만 허용
                guard foodOnlySingles.contains(w) else { continue }

