            .replacingOccurrences(of: ",", with: "")
            .components(separatedBy: " ")
            .filter { !$0.isEmpty }

        for i in 0..<(tokens.count - 1) {

            let current = tokens[i]
            let next = tokens[i + 1]

            // 🔥 기존 유지
            if next.contains("$"),
               let value = Double(current),
               value > 0 && value < 100 {

                candidates.append(value)
            }
        }
    }

    // =================================================
    // 2️⃣ NEW: CCF 기반 (table 구조 대응)
    // =================================================
    if candidates.isEmpty {

