    if t.contains("coolant") || t.contains("radiator") || t.contains("thermostat") {
        return "cooling"
    }

    // =========================
    // Air intake
    // =========================
    if t.contains("air") || t.contains("intake") || t.contains("maf") {
        return "air"
    }

    // =========================
    // EVAP
    // =========================
    if t.contains("evap") {
        return "evap"
    }

    // =========================
    // Exhaust
