                nutriScore: getString(19),
                novaGroup: getInt(20)
            )
            print("✅ Found match in DB: \(found!.name)")
        }

        sqlite3_finalize(stmt)
        return found
    }

    if let p = runQuery(rawCode) { return p }
    if cleaned != rawCode {
        if let p = runQuery(cleaned) { return p }
