            (UPPER(TRIM(f.drug_a)) = ? AND UPPER(TRIM(f.drug_b)) = ?)
            OR
            (UPPER(TRIM(f.drug_a)) = ? AND UPPER(TRIM(f.drug_b)) = ?)
          )
        ORDER BY s.odds_ratio DESC
        LIMIT \(limit)
        """
    }

