    sqlite3_bind_text(stmt, 1, a, -1, SQLITE_TRANSIENT)
    sqlite3_bind_text(stmt, 2, b, -1, SQLITE_TRANSIENT)
    sqlite3_bind_text(stmt, 3, b, -1, SQLITE_TRANSIENT)
    sqlite3_bind_text(stmt, 4, a, -1, SQLITE_TRANSIENT)

