        }

        // attention mask: padding이 아닌 곳은 1, padding은 0
        var attentionMask = [Int64](repeating: 0, count: maxLength)
        for i in 0..<maxLength {
            if tokenIds[i] != padId {
                attentionMask[i] = 1
            }
        }

        return (tokenIds, attentionMask)
    }

